module comb_op
(
  input [3:0] input_signal,
  output reg [3:0] out
);

  always @(*)
  begin
    if (input_signal >= 0 && input_signal <= 7) // Range 0 to 7
      out = input_signal << 1;
    else if (input_signal >= 8 && input_signal <= 15) // Range 8 to 15
      out = input_signal >> 1;
    else // Outside range 0 to 15
      out = 0;
  end

endmodule
